// Map GeoJSON country NAME -> the country key used in our dot data.
const COUNTRY_TO_DOTKEY = {
  "United States of America": "United States",
  "Canada": "Canada",
};

function pointInPolygon(lng, lat, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    if (((yi > lat) !== (yj > lat)) &&
        (lng < ((xj - xi) * (lat - yi)) / (yj - yi) + xi)) {
      inside = !inside;
    }
  }
  return inside;
}

// Centroid + bbox of a GeoJSON feature's largest ring (for camera centering).
function featureFrame(feat) {
  const g = feat.geometry;
  const polys = g.type === "MultiPolygon" ? g.coordinates : [g.coordinates];
  let bigRing = null, bigLen = 0;
  for (const poly of polys) {
    const ring = poly[0];
    if (ring.length > bigLen) { bigLen = ring.length; bigRing = ring; }
  }
  let cLat = 0, cLng = 0;
  if (bigRing) {
    for (const [lng, lat] of bigRing) { cLng += lng; cLat += lat; }
    cLat /= bigRing.length; cLng /= bigRing.length;
  }
  return { lat: cLat, lng: cLng };
}

// Convert our US_STATES_GEO ({postal:{name,rings,c}}) into GeoJSON features that
// globe.gl can render, tagged so we can identify them on hover/click.
function statesToFeatures(statesGeo) {
  if (!statesGeo) return [];
  const feats = [];
  for (const [postal, st] of Object.entries(statesGeo)) {
    feats.push({
      type: "Feature",
      properties: { __state: true, postal, NAME: st.name, c: st.c },
      geometry: {
        type: "Polygon",
        coordinates: [st.rings[0]],
      },
    });
  }
  return feats;
}

// Right-side panel showing a single company's open roles, with apply toggles
// that write through to the shared applications store (synced with the job board).
function CompanyPanel({ company, jobs, user, onClose, onApplied, onRemoveApplied }) {
  const applied = user?.applied || {};
  return (
    <div
      style={{
        position: "absolute",
        right: 0,
        top: 0,
        bottom: 0,
        width: 380,
        maxWidth: "92vw",
        background: "linear-gradient(180deg, rgba(16,11,7,.98), rgba(8,6,8,.98))",
        borderLeft: "1px solid rgba(201,168,76,.3)",
        boxShadow: "-12px 0 40px rgba(0,0,0,.5)",
        display: "flex",
        flexDirection: "column",
        zIndex: 60,
        animation: "mqPanelIn .28s ease",
      }}
    >
      <style>{`@keyframes mqPanelIn{from{transform:translateX(40px);opacity:0}to{transform:translateX(0);opacity:1}}`}</style>

      {/* Header */}
      <div style={{ padding: "18px 20px 14px", borderBottom: "1px solid rgba(201,168,76,.15)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10 }}>
          <div>
            <div style={{ fontFamily: "'Cinzel',serif", fontSize: 17, fontWeight: 700, color: GOLD_BRIGHT, lineHeight: 1.2 }}>
              {company.name}
            </div>
            <div style={{ fontSize: 11, color: "rgba(244,237,216,.55)", marginTop: 4 }}>
              {jobs.length} open {jobs.length === 1 ? "role" : "roles"}
              {company.state ? ` · ${company.state}` : ""}
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: "rgba(201,168,76,.1)",
              border: "1px solid rgba(201,168,76,.3)",
              color: GOLD_BRIGHT,
              cursor: "pointer",
              borderRadius: 8,
              width: 28,
              height: 28,
              fontSize: 14,
              flexShrink: 0,
              fontFamily: "'Cinzel',serif",
            }}
          >
            ✕
          </button>
        </div>
      </div>

      {/* Job list */}
      <div style={{ flex: 1, overflowY: "auto", padding: "12px 16px 20px", display: "flex", flexDirection: "column", gap: 10 }}>
        {jobs.length === 0 && (
          <div style={{ color: "rgba(244,237,216,.5)", fontSize: 12.5, textAlign: "center", marginTop: 30, lineHeight: 1.6 }}>
            No open roles listed right now.<br />Check back later on your journey.
          </div>
        )}
        {jobs.map((job) => {
          const isApplied = !!applied[job.id];
          return (
            <div
              key={job.id}
              style={{
                background: isApplied ? "rgba(126,207,179,.06)" : "rgba(201,168,76,.05)",
                border: `1px solid ${isApplied ? "rgba(126,207,179,.3)" : "rgba(201,168,76,.18)"}`,
                borderRadius: 10,
                padding: "12px 14px",
                opacity: isApplied ? 0.72 : 1,
                transition: "opacity .25s, background .25s, border .25s",
              }}
            >
              <div style={{ display: "flex", justifyContent: "space-between", gap: 8, alignItems: "flex-start" }}>
                <div style={{ fontSize: 13.5, fontWeight: 600, color: "#f4edd8", lineHeight: 1.3 }}>
                  {job.title}
                </div>
                {job.isNew && (
                  <span style={{ fontSize: 8.5, fontWeight: 800, color: "#0a0608", background: GOLD, borderRadius: 20, padding: "2px 6px", flexShrink: 0, fontFamily: "'Cinzel',serif" }}>
                    NEW
                  </span>
                )}
              </div>

              {/* Meta chips */}
              <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginTop: 8 }}>
                {job.type && chipize(job.type)}
                {job.isRemote && chipize("Remote OK")}
                {job.salary && job.salary !== "Salary not listed" && chipize(job.salary)}
                {job.locationLabel && job.locationLabel !== "Other" && chipize(job.locationLabel)}
              </div>

              {/* Actions */}
              <div style={{ display: "flex", gap: 8, marginTop: 11, alignItems: "center" }}>
                <a
                  href={job.applyUrl || job.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  style={{
                    fontSize: 11,
                    fontWeight: 700,
                    color: GOLD_BRIGHT,
                    textDecoration: "none",
                    fontFamily: "'Cinzel',serif",
                    border: "1px solid rgba(201,168,76,.35)",
                    borderRadius: 7,
                    padding: "6px 11px",
                  }}
                >
                  View Posting
                </a>
                {isApplied ? (
                  <button
                    onClick={() => onRemoveApplied && onRemoveApplied(job.id)}
                    style={{
                      fontSize: 11,
                      fontWeight: 700,
                      color: "#7ecfb3",
                      background: "rgba(126,207,179,.1)",
                      border: "1px solid rgba(126,207,179,.35)",
                      borderRadius: 7,
                      padding: "6px 11px",
                      cursor: "pointer",
                      fontFamily: "'Cinzel',serif",
                      display: "flex",
                      alignItems: "center",
                      gap: 5,
                    }}
                  >
                    ✓ Applied
                  </button>
                ) : (
                  <button
                    onClick={() => onApplied && onApplied(job.id)}
                    style={{
                      fontSize: 11,
                      fontWeight: 800,
                      color: "#0a0608",
                      background: `linear-gradient(135deg,${GOLD},${ORANGE})`,
                      border: "none",
                      borderRadius: 7,
                      padding: "6px 13px",
                      cursor: "pointer",
                      fontFamily: "'Cinzel',serif",
                    }}
                  >
                    Mark Applied
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// Small chip helper for the panel meta row.
function chipize(text) {
  return (
    <span
      key={text}
      style={{
        fontSize: 9.5,
        color: "rgba(244,237,216,.65)",
        background: "rgba(201,168,76,.08)",
        border: "1px solid rgba(201,168,76,.16)",
        borderRadius: 20,
        padding: "2px 8px",
        whiteSpace: "nowrap",
      }}
    >
      {text}
    </span>
  );
}

export default function JourneyGlobe({ user, dots = [], statesGeo = null, provincesGeo = null, getCompanyJobs = null, onApplied = null, onRemoveApplied = null, onExit }) {
  const mountRef = useRef(null);
  const globeRef = useRef(null);
  const dotsRef = useRef(dots);
  const countryFeatsRef = useRef([]);    // country polygons
  const stateFeatsRef = useRef([]);      // US/Canada state polygons (all)
  const navRef = useRef({ level: "continent", continent: null, country: null, state: null });
  const hoverRef = useRef(null);
  const hoveredDotRef = useRef(null);
  const getCompanyJobsRef = useRef(getCompanyJobs);
  const refreshLabelsRef = useRef(null);
  const repaintRef = useRef(null);
  getCompanyJobsRef.current = getCompanyJobs;
  const lastScrollRef = useRef(0);

  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState("");
  const [nav, setNav] = useState({ level: "continent", continent: null, country: null, state: null });
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [panelJobs, setPanelJobs] = useState([]);

  dotsRef.current = dots;
  const provinceFeatsRef = useRef([]);
  stateFeatsRef.current = stateFeatsRef.current.length
    ? stateFeatsRef.current
    : statesToFeatures(statesGeo);
  provinceFeatsRef.current = provinceFeatsRef.current.length
    ? provinceFeatsRef.current
    : statesToFeatures(provincesGeo);

  const setNavBoth = (next) => {
    navRef.current = next;
    setNav(next);
  };

  useEffect(() => {
    if (!mountRef.current) return;
    let globe;
    let disposed = false;
    let onResize, onWheel;

    try {
      globe = Globe({
        rendererConfig: { antialias: true, alpha: true },
        animateIn: false,
      })(mountRef.current);
      globeRef.current = globe;

      globe
        .backgroundColor("rgba(0,0,0,0)")
        .showGlobe(true)
        .showAtmosphere(true)
        .atmosphereColor(GOLD)
        .atmosphereAltitude(0.18)
        .width(mountRef.current.clientWidth)
        .height(mountRef.current.clientHeight);

      // Sharper rendering to reduce limb shimmer on outlines.
      try {
        const renderer = globe.renderer && globe.renderer();
        if (renderer) renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
      } catch (e) {}

      const mat = globe.globeMaterial();
      if (mat) {
        mat.color && mat.color.set("#140d09");
        mat.emissive && mat.emissive.set("#1a1008");
        mat.emissiveIntensity = 0.35;
        mat.shininess = 6;
      }

      // Instant polygon swaps (no altitude animation) — the default 1s transition
      // animates cones up from the surface and briefly flashes their dark sides,
      // which looked like black blotches when zooming/changing levels.
      globe.polygonsTransitionDuration(0);

      const controls = globe.controls();
      if (controls) {
        controls.autoRotate = true;
        controls.autoRotateSpeed = 0.3;
        controls.enableZoom = false;
        controls.enablePan = false;
        controls.screenSpacePanning = false;
        controls.minDistance = 101 * (1 + ALT_STATE_LOCK);
        controls.maxDistance = 101 * (1 + ALT_CONTINENT_SELECT);
        controls.rotateSpeed = 0.8;
        if (controls.mouseButtons) {
          controls.mouseButtons.LEFT = 0;
          controls.mouseButtons.RIGHT = 0;
        }
        const stopSpin = () => { controls.autoRotate = false; };
        controls.addEventListener("start", stopSpin);
      }

      const applyLevelControls = () => {
        const c = globe.controls();
        if (!c) return;
        const lvl = navRef.current.level;
        c.enableRotate = lvl === "continent";
        if (lvl !== "continent") c.autoRotate = false;
      };

      const flyTo = (lat, lng, altitude) => {
        globe.pointOfView({ lat, lng, altitude }, LERP_MS);
      };

      globe.pointOfView({ lat: 30, lng: -60, altitude: ALT_CONTINENT_SELECT }, 0);

      const inActiveContinent = (d) =>
        navRef.current.continent &&
        d.properties.CONTINENT === navRef.current.continent;
      const isHovered = (d) => hoverRef.current && d === hoverRef.current;
      const isStateFeat = (d) => d && d.properties && d.properties.__state;

      // Which polygons are active for the current level.
      const polygonsForLevel = () => {
        const lvl = navRef.current.level;
        if (lvl === "continent") {
          // Dissolved continent outlines — clean coastline, blank interior, no
          // internal country borders.
          return CONTINENT_SHAPES.features;
        }
        if (lvl === "state" || lvl === "local") {
          const dotKey = COUNTRY_TO_DOTKEY[navRef.current.country];
          if (dotKey === "United States") return stateFeatsRef.current;
          if (dotKey === "Canada") return provinceFeatsRef.current;
          return countryFeatsRef.current;
        }
        return countryFeatsRef.current;
      };

      // Resolve the sub-region geo set (US states or CA provinces) for a country.
      const subGeoFor = (countryName) => {
        const dk = COUNTRY_TO_DOTKEY[countryName];
        if (dk === "United States") return statesGeo;
        if (dk === "Canada") return provincesGeo;
        return null;
      };

      // ── Fog of war ────────────────────────────────────────────────────────
      // A state/province is "explored" once you've applied to at least one of its
      // companies. Unexplored regions are veiled in a pale cloud-fog that lifts as
      // you apply. We compute an explored-fraction per state for subtle shading
      // (more applied companies → thinner fog).
      const stateFog = (d) => {
        // d is a state/province polygon feature with properties.postal + .country-ish.
        const postal = d.properties.postal;
        if (!postal) return 1; // unknown → fully fogged
        const dots = dotsRef.current || [];
        // Match dots to this polygon by postal code.
        let total = 0, explored = 0;
        for (const dt of dots) {
          if (dt.postal !== postal) continue;
          total++;
          if (dt.applied) explored++;
        }
        if (total === 0) return 0.85;          // no companies here → light haze, not solid
        if (explored === 0) return 1;          // none explored → full fog
        const frac = explored / total;
        return Math.max(0, 1 - frac);          // thins as you explore
      };
      // Fog fill color for a given fog amount (0 = clear, 1 = full cloud).
      const fogCap = (amt) => `rgba(214,214,222,${(amt * 0.34).toFixed(3)})`;

      const capColor = (d) => {
        const lvl = navRef.current.level;
        if (lvl === "continent") {
          // Blank middle by default; the whole continent fills gold on hover.
          if (hoverRef.current &&
              d.properties.CONTINENT === hoverRef.current.properties.CONTINENT)
            return "rgba(240,208,128,0.26)";
          return "rgba(0,0,0,0)"; // fully transparent — blank interior
        }
        if (lvl === "country") {
          if (!inActiveContinent(d)) return "rgba(201,168,76,0.03)";
          if (isHovered(d)) return "rgba(240,208,128,0.30)";
          return "rgba(201,168,76,0.10)";
        }
        // state / local levels — working with state polygons
        if (isStateFeat(d)) {
          if (navRef.current.state && d.properties.postal === navRef.current.state)
            return "rgba(201,168,76,0.02)"; // locked state: outline only
          if (isHovered(d)) return "rgba(240,208,128,0.30)";
          // Veil unexplored regions in cloud-fog; it thins as you apply.
          const amt = stateFog(d);
          if (amt > 0.001) return fogCap(amt);
          return "rgba(201,168,76,0.08)";
        }
        return "rgba(201,168,76,0.02)";
      };

      const strokeColor = (d) => {
        const lvl = navRef.current.level;
        if (lvl === "continent") {
          // Faint gold outlines trace each continent's coastline; the hovered
          // continent's outline brightens. (Interiors stay blank — see capColor.)
          if (hoverRef.current &&
              d.properties.CONTINENT === hoverRef.current.properties.CONTINENT)
            return "rgba(255,225,166,0.95)";
          return "rgba(214,182,99,0.45)";
        }
        if (lvl === "country") {
          if (!inActiveContinent(d)) return "rgba(214,182,99,0.15)";
          if (isHovered(d)) return "rgba(255,225,166,0.95)";
          return "rgba(214,182,99,0.55)";
        }
        // state / local
        if (isStateFeat(d)) {
          if (navRef.current.state && d.properties.postal === navRef.current.state)
            return "rgba(255,225,166,0.95)";
          if (isHovered(d)) return "rgba(255,225,166,0.95)";
          return "rgba(214,182,99,0.5)";
        }
        return "rgba(214,182,99,0.2)";
      };

      // Keep polygons flat against the surface (prevents edge-on limb shimmer).
      const polyAlt = () => 0.004;

      const repaint = () => {
        const g = globeRef.current;
        if (!g) return;
        g.polygonsData(polygonsForLevel())
          .polygonCapColor(capColor)
          .polygonStrokeColor(strokeColor)
          .polygonSideColor(strokeColor)
          .polygonAltitude(polyAlt);
      };
      repaintRef.current = repaint;

      // ── Company dots ──────────────────────────────────────────────────────
      // Shown only at the "local" level, for the locked state.
      const visibleDots = () => {
        const lvl = navRef.current.level;
        // Show dots once a country is locked (state level) and when zoomed into a
        // single state (local level).
        if (lvl === "local") {
          const postal = navRef.current.state;
          const geo = subGeoFor(navRef.current.country);
          if (!postal || !geo || !geo[postal]) return [];
          const stateName = geo[postal].name;
          return dotsRef.current.filter((dt) => dt.state === stateName);
        }
        if (lvl === "state") {
          const dotKey = COUNTRY_TO_DOTKEY[navRef.current.country];
          if (!dotKey) return [];
          return dotsRef.current.filter((dt) => dt.country === dotKey);
        }
        return [];
      };

      const refreshDots = () => {
        const g = globeRef.current;
        if (!g) return;
        g.pointsData(visibleDots())
          .pointLat((d) => d.lat)
          .pointLng((d) => d.lng)
          .pointAltitude(0.004)
          .pointRadius((d) =>
            hoveredDotRef.current === d
              ? (d.applied ? 0.13 : 0.12)   // grow slightly on hover
              : (d.applied ? 0.08 : 0.07)   // small circular dots
          )
          .pointColor((d) =>
            d.applied ? "rgba(126,207,179,0.97)" : "rgba(255,207,122,0.98)"
          )
          .pointResolution(12)
          .onPointHover((d) => {
            // Dots are only interactive at the local (state/province) level.
            if (navRef.current.level !== "local") {
              hoveredDotRef.current = null;
              return;
            }
            hoveredDotRef.current = d || null;
            const g2 = globeRef.current;
            if (g2) g2.pointRadius(g2.pointRadius());
            if (mountRef.current)
              mountRef.current.style.cursor = d ? "pointer" : "grab";
          })
          .pointLabel((d) =>
            navRef.current.level !== "local"
              ? ""
              : `<div style="font-family:'Cinzel',serif;color:${GOLD_BRIGHT};background:rgba(12,9,6,.92);border:1px solid rgba(201,168,76,.45);padding:5px 11px;border-radius:7px;font-size:12px;white-space:nowrap"><strong>${
                  d.name
                }</strong>${
                  d.jobCount
                    ? `<span style="color:rgba(244,237,216,.6);font-size:10px"> · ${d.jobCount} open</span>`
                    : ""
                }</div>`
          )
          .onPointClick((d) => {
            if (navRef.current.level !== "local") return; // not clickable at country view
            if (d && d.name) {
              setSelectedCompany(d);
              // Pull the company's real jobs (live ATS + overrides) for the panel.
              const jobs = getCompanyJobsRef.current
                ? getCompanyJobsRef.current(d.name)
                : [];
              setPanelJobs(jobs || []);
            }
          });
      };

      // ── Drill-down click handler ──────────────────────────────────────────
      const handlePolyClick = (d) => {
        if (!d) return;
        const lvl = navRef.current.level;
        if (lvl === "continent") {
          const cont = d.properties.CONTINENT;
          if (!cont || !CONTINENTS[cont]) return;
          const c = CONTINENTS[cont];
          setNavBoth({ level: "country", continent: cont, country: null, state: null });
          flyTo(c.lat, c.lng, ALT_CONTINENT_LOCK);
        } else if (lvl === "country") {
          if (d.properties.CONTINENT !== navRef.current.continent) return;
          const frame = featureFrame(d);
          setNavBoth({
            level: "state",
            continent: navRef.current.continent,
            country: d.properties.NAME,
            state: null,
          });
          flyTo(frame.lat, frame.lng, ALT_COUNTRY_LOCK);
        } else if (lvl === "state") {
          if (!isStateFeat(d)) return;
          const geo = subGeoFor(navRef.current.country);
          const st = geo && geo[d.properties.postal];
          const center = st ? st.c : featureFrame(d);
          const lat = Array.isArray(center) ? center[1] : center.lat;
          const lng = Array.isArray(center) ? center[0] : center.lng;
          setNavBoth({
            level: "local",
            continent: navRef.current.continent,
            country: navRef.current.country,
            state: d.properties.postal,
          });
          flyTo(lat, lng, ALT_STATE_LOCK);
        }
        setTimeout(() => {
          applyLevelControls();
          repaint();
          refreshDots();
          refreshLabels();
        }, LERP_MS + 40);
        repaint();
        refreshLabels();
      };

      // ── Scroll-out: back up one level (throttled) ─────────────────────────
      onWheel = (e) => {
        e.preventDefault();
        if (e.deltaY <= 0) return;
        const now = Date.now();
        if (now - lastScrollRef.current < SCROLL_COOLDOWN_MS) return;
        const n = navRef.current;
        if (n.level === "local") {
          lastScrollRef.current = now;
          const frame = (() => {
            const f = countryFeatsRef.current.find((c) => c.properties.NAME === n.country);
            return f ? featureFrame(f) : { lat: 38, lng: -97 };
          })();
          setSelectedCompany(null);
          // Back to the whole-country state view — dots for the whole country show.
          setNavBoth({ level: "state", continent: n.continent, country: n.country, state: null });
          flyTo(frame.lat, frame.lng, ALT_COUNTRY_LOCK);
          setTimeout(() => { applyLevelControls(); repaint(); refreshDots(); refreshLabels(); }, LERP_MS + 40);
          repaint();
          refreshDots();
          refreshLabels();
        } else if (n.level === "state") {
          lastScrollRef.current = now;
          const c = CONTINENTS[n.continent] || { lat: 30, lng: -60 };
          globe.pointsData([]); // country level shows no dots
          setNavBoth({ level: "country", continent: n.continent, country: null, state: null });
          flyTo(c.lat, c.lng, ALT_CONTINENT_LOCK);
          setTimeout(() => { applyLevelControls(); repaint(); refreshLabels(); }, LERP_MS + 40);
          repaint();
          refreshLabels();
        } else if (n.level === "country") {
          lastScrollRef.current = now;
          const outLng = n.continent && CONTINENTS[n.continent] ? CONTINENTS[n.continent].lng : -60;
          setNavBoth({ level: "continent", continent: null, country: null, state: null });
          flyTo(30, outLng, ALT_CONTINENT_SELECT);
          setTimeout(() => { applyLevelControls(); repaint(); refreshLabels(); }, LERP_MS + 40);
          repaint();
          refreshLabels();
        }
      };
      mountRef.current.addEventListener("wheel", onWheel, { passive: false });

      // ── Floating progress labels (continents at top level, countries after) ─
      // Uses globe.gl's HTML elements layer. Each label shows a name and a
      // "Progression %" sub-line (placeholder 0% until exploration tracking lands).
      const COUNTRY_LABEL_CENTERS = {
        "United States of America": { lat: 39.5, lng: -98 },
        "Canada": { lat: 56, lng: -96 },
        "Mexico": { lat: 23.5, lng: -102 },
      };

      // ── Exploration progress (Option A: company-based) ──────────────────
      // A company counts as "explored" once you've applied to at least one of
      // its jobs (dot.applied === true). Progress for a region = explored
      // companies / total companies in that region. Country dots map into their
      // continent so the continent label aggregates its countries.
      const DOTKEY_CONTINENT = { "United States": "North America", "Canada": "North America" };
      const computeProgress = () => {
        const dots = dotsRef.current || [];
        const byCountry = {};   // dotKey -> { total, explored }
        const byContinent = {}; // continent -> { total, explored }
        for (const d of dots) {
          const ck = d.country;
          const cont = DOTKEY_CONTINENT[ck] || null;
          if (!byCountry[ck]) byCountry[ck] = { total: 0, explored: 0 };
          byCountry[ck].total++;
          if (d.applied) byCountry[ck].explored++;
          if (cont) {
            if (!byContinent[cont]) byContinent[cont] = { total: 0, explored: 0 };
            byContinent[cont].total++;
            if (d.applied) byContinent[cont].explored++;
          }
        }
        const pct = (o) => (o && o.total ? Math.round((o.explored / o.total) * 100) : 0);
        return {
          country: (ck) => pct(byCountry[ck]),
          continent: (cont) => pct(byContinent[cont]),
        };
      };

      const buildLabelData = () => {
        const lvl = navRef.current.level;
        const prog = computeProgress();
        if (lvl === "continent") {
          return Object.entries(CONTINENTS).map(([name, c]) => ({
            id: "cont-" + name,
            lat: c.lat,
            lng: c.lng,
            name,
            progress: prog.continent(name),
          }));
        }
        if (lvl === "country") {
          // Only the United States and Canada have progression labels for now.
          const LABELED = { "United States of America": 1, "Canada": 1 };
          const cont = navRef.current.continent;
          const seen = {};
          const out = [];
          for (const f of countryFeatsRef.current) {
            if (f.properties.CONTINENT !== cont) continue;
            const name = f.properties.NAME;
            if (!LABELED[name] || seen[name]) continue;
            seen[name] = true;
            const center =
              COUNTRY_LABEL_CENTERS[name] || featureFrame(f);
            const display = name === "United States of America" ? "United States" : name;
            out.push({
              id: "ctry-" + name,
              lat: center.lat,
              lng: center.lng,
              name: display,
              progress: prog.country(display),
            });
          }
          return out;
        }
        return []; // no floating labels at state/local level
      };

      const makeLabelEl = (d) => {
        const el = document.createElement("div");
        el.style.cssText =
          "pointer-events:none;text-align:center;transform:translate(-50%,-50%);" +
          "font-family:'Cinzel',serif;white-space:nowrap;";
        el.innerHTML =
          `<div style="font-size:15px;font-weight:700;letter-spacing:.5px;` +
          `color:#ffe9b8;text-shadow:0 0 8px rgba(240,208,128,.8),0 0 16px rgba(232,97,58,.5);">${d.name}</div>` +
          `<div style="font-size:9px;letter-spacing:.5px;margin-top:1px;` +
          `color:#f0d080;text-shadow:0 0 6px rgba(240,208,128,.6);opacity:.85;">Progression ${d.progress}%</div>`;
        return el;
      };

      const refreshLabels = () => {
        const g = globeRef.current;
        if (!g) return;
        g.htmlElementsData(buildLabelData())
          .htmlLat((d) => d.lat)
          .htmlLng((d) => d.lng)
          .htmlAltitude(0.06)
          .htmlElement(makeLabelEl);
      };
      refreshLabelsRef.current = refreshLabels;

      // ── Load country polygons ─────────────────────────────────────────────
      fetch(COUNTRIES_URL)
        .then((r) => r.json())
        .then((geo) => {
          if (disposed) return;
          const feats = (geo.features || []).filter(
            (d) => d.properties && d.properties.NAME !== "Antarctica"
          );
          countryFeatsRef.current = feats;
          globe
            .polygonsData(polygonsForLevel())
            .polygonAltitude(polyAlt)
            .polygonCapColor(capColor)
            .polygonSideColor(strokeColor)
            .polygonStrokeColor(strokeColor)
            .onPolygonHover((d) => {
              hoverRef.current = d || null;
              repaint();
              if (mountRef.current)
                mountRef.current.style.cursor = d ? "pointer" : "grab";
            })
            .onPolygonClick((d) => handlePolyClick(d))
            .polygonLabel((d) => {
              const lvl = navRef.current.level;
              const txt =
                lvl === "continent" ? d.properties.CONTINENT : d.properties.NAME;
              return `<div style="font-family:'Cinzel',serif;color:${GOLD_BRIGHT};background:rgba(12,9,6,.92);border:1px solid rgba(201,168,76,.45);padding:4px 11px;border-radius:7px;font-size:12px;white-space:nowrap">${
                txt || ""
              }</div>`;
            });
          applyLevelControls();
          refreshLabels();
          setLoading(false);
        })
        .catch(() => {
          if (disposed) return;
          setErr("Could not load map data. Check your connection and try again.");
          setLoading(false);
        });

      onResize = () => {
        if (!mountRef.current || !globeRef.current) return;
        globeRef.current
          .width(mountRef.current.clientWidth)
          .height(mountRef.current.clientHeight);
      };
      window.addEventListener("resize", onResize);
    } catch (e) {
      setErr("3D globe failed to initialize on this device.");
      setLoading(false);
    }

    return () => {
      disposed = true;
      if (onResize) window.removeEventListener("resize", onResize);
      if (onWheel && mountRef.current)
        mountRef.current.removeEventListener("wheel", onWheel);
      try {
        if (globeRef.current && globeRef.current._destructor) {
          globeRef.current._destructor();
        }
      } catch (e) {}
      if (mountRef.current) mountRef.current.innerHTML = "";
      globeRef.current = null;
    };
  }, []);

  // Keep dots synced if the prop changes while dots are visible.
  useEffect(() => {
    const globe = globeRef.current;
    if (!globe) return;
    const lvl = navRef.current.level;
    if (lvl === "local") {
      const postal = navRef.current.state;
      const geo = navRef.current.country === "Canada" ? provincesGeo : statesGeo;
      if (!postal || !geo || !geo[postal]) return;
      const stateName = geo[postal].name;
      globe.pointsData(dots.filter((dt) => dt.state === stateName));
    } else if (lvl === "state") {
      const dotKey = navRef.current.country === "United States of America"
        ? "United States"
        : navRef.current.country === "Canada" ? "Canada" : null;
      if (dotKey) globe.pointsData(dots.filter((dt) => dt.country === dotKey));
    }
    // Applications may have changed (dot.applied), so refresh progress labels
    // and repaint the fog of war.
    if (refreshLabelsRef.current) refreshLabelsRef.current();
    if (repaintRef.current) repaintRef.current();
  }, [dots, statesGeo]);

  const crumb =
    nav.level === "continent"
      ? "Choose a continent"
      : nav.level === "country"
      ? `${nav.continent} — choose a country`
      : nav.level === "state"
      ? `${nav.country} — choose a state`
      : (() => {
          const geo = nav.country === "Canada" ? provincesGeo : statesGeo;
          return geo && geo[nav.state] ? geo[nav.state].name : "Explore";
        })();

  const hint =
    nav.level === "continent"
      ? "Drag to rotate · click a continent to travel there"
      : nav.level === "country"
      ? "Click a country to explore it · scroll out to go back"
      : nav.level === "state"
      ? "Click a state to zoom in · scroll out to go back"
      : "Click a marker to view the studio · scroll out to go back";

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: `radial-gradient(ellipse at 50% 35%, #160e0a 0%, ${DARK} 70%)`,
        zIndex: 50,
        overflow: "hidden",
      }}
    >
      <div ref={mountRef} style={{ width: "100%", height: "100%", cursor: "grab" }} />

      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "16px 20px",
          pointerEvents: "none",
        }}
      >
        <div style={{ pointerEvents: "auto" }}>
          <div
            style={{
              fontFamily: "'Cinzel Decorative',serif",
              fontSize: 22,
              fontWeight: 700,
              background: `linear-gradient(135deg,${GOLD_BRIGHT},${ORANGE})`,
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              letterSpacing: 1,
            }}
          >
            Journey Mode
          </div>
          <div style={{ fontSize: 12, color: GOLD_BRIGHT, marginTop: 3, fontFamily: "'Cinzel',serif", letterSpacing: 0.4 }}>
            {crumb}
          </div>
          <div style={{ fontSize: 11, color: "rgba(244,237,216,.5)", marginTop: 2 }}>
            {hint}
          </div>
        </div>
        <button
          onClick={onExit}
          style={{
            pointerEvents: "auto",
            background: "rgba(201,168,76,.08)",
            border: "1px solid rgba(201,168,76,.3)",
            color: GOLD_BRIGHT,
            cursor: "pointer",
            borderRadius: 10,
            padding: "9px 16px",
            fontSize: 12,
            fontWeight: 700,
            fontFamily: "'Cinzel',serif",
            letterSpacing: 0.5,
          }}
        >
          ← Back to Job Board
        </button>
      </div>

      {/* Company panel — real job listings, apply synced with the job board */}
      {selectedCompany && (
        <CompanyPanel
          company={selectedCompany}
          jobs={panelJobs}
          user={user}
          onClose={() => { setSelectedCompany(null); setPanelJobs([]); }}
          onApplied={onApplied}
          onRemoveApplied={onRemoveApplied}
        />
      )}

      {loading && !err && (
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: GOLD,
            fontFamily: "'Cinzel',serif",
            fontSize: 14,
            letterSpacing: 1,
            pointerEvents: "none",
          }}
        >
          Charting the realm…
        </div>
      )}
      {err && (
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            gap: 12,
            color: "rgba(244,237,216,.7)",
            fontSize: 13,
            padding: 24,
            textAlign: "center",
          }}
        >
          {err}
          <button
            onClick={onExit}
            style={{
              background: `linear-gradient(135deg,${GOLD},${ORANGE})`,
              border: "none",
              color: DARK,
              cursor: "pointer",
              borderRadius: 10,
              padding: "10px 20px",
              fontSize: 12,
              fontWeight: 800,
              fontFamily: "'Cinzel',serif",
            }}
          >
            ← Back to Job Board
          </button>
        </div>
      )}
    </div>
  );
}